import React, { useState, useEffect } from "react";

function RouteForm({ onNewRoute }) { // onNewRoute — callback для обновления таблицы
  const [stations, setStations] = useState([]);
  const [trains, setTrains] = useState([]);
  const [departure, setDeparture] = useState("");
  const [arrival, setArrival] = useState("");
  const [selectedTrain, setSelectedTrain] = useState("");

  useEffect(() => {
    fetch("http://localhost:5050/stations")
      .then(res => res.json())
      .then(setStations)
      .catch(console.error);

    fetch("http://localhost:5050/trains")
      .then(res => res.json())
      .then(setTrains)
      .catch(console.error);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!departure || !arrival || !selectedTrain) {
      alert("Выберите все поля");
      return;
    }

    try {
      const res = await fetch("http://localhost:5050/routes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          departure_station: departure,
          arrival_station: arrival,
          train_id: parseInt(selectedTrain)
        })
      });
      const data = await res.json();
      if (!res.ok) {
        alert(data.error || "Ошибка");
        return;
      }

      alert("Маршрут добавлен ✅");
      setDeparture("");
      setArrival("");
      setSelectedTrain("");

      if (onNewRoute) onNewRoute(data); // обновляем таблицу сразу
    } catch (err) {
      console.error(err);
      alert("Ошибка соединения");
    }
  };

  return (
    <div>
      <h2>Add Route</h2>
      <form onSubmit={handleSubmit}>
        <select value={departure} onChange={e => setDeparture(e.target.value)}>
          <option value="">Выберите станцию отправления</option>
          {stations.map(st => <option key={st.id} value={st.name}>{st.name}</option>)}
        </select>

        <select value={arrival} onChange={e => setArrival(e.target.value)}>
          <option value="">Выберите станцию прибытия</option>
          {stations.map(st => <option key={st.id} value={st.name}>{st.name}</option>)}
        </select>

        <select value={selectedTrain} onChange={e => setSelectedTrain(e.target.value)}>
          <option value="">Выберите поезд</option>
          {trains.map(tr => <option key={tr.id} value={tr.id}>{tr.name}</option>)}
        </select>

        <button type="submit">Add</button>
      </form>
    </div>
  );
}

export default RouteForm;
